  1228 | static Instruction *foldAddToAshr(BinaryOperator &Add) {
  1229 |   // Division must be by power-of-2, but not the minimum signed value.
  1230 |   Value *X;
  1231 |   const APInt *DivC;
  1232 |   if (!match(Add.getOperand(0), m_SDiv(m_Value(X), m_Power2(DivC))) ||
  1233 |       DivC->isNegative())
  1234 |     return nullptr;
  1235 | 
  1236 |   // Rounding is done by adding -1 if the dividend (X) is negative and has any
  1237 |   // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
  1238 |   // sext (icmp ugt (X & (DivC - 1)), SMIN)
  1239 |   // Or: sext (icmp eq (X & (DivC - 1)), (DivC - 1)) - if DivC is 2
  1240 |   const APInt *MaskC;
  1241 |   ICmpInst::Predicate Pred;
  1242 |   const APInt *CmpC;
  1243 |   if (!match(Add.getOperand(1),
  1244 |              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
  1245 |                            m_APInt(CmpC)))))
  1246 |     return nullptr;
  1247 |   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
  1248 |   if (Pred == ICmpInst::ICMP_UGT && CmpC->isSignMask() &&
  1249 |       *MaskC == (SMin | (*DivC - 1))) {
  1250 |     // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
  1251 |     return BinaryOperator::CreateAShr(
  1252 |         X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
  1253 |   }
  1254 | 
  1255 |   if (Pred == ICmpInst::ICMP_EQ && *CmpC == (SMin | (*DivC - 1)) &&
  1256 |       *MaskC == (SMin | (*DivC - 1))) {
  1257 |     // (X / DivC) + sext ((X & (SMin | (DivC - 1)) == (SMin | DivC - 1)) --> X >>s log2(DivC)
  1258 |     return BinaryOperator::CreateAShr(
  1259 |         X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
  1260 |   }
